@Test
public void testOverrideMeanWithCustomClass() throws Exception {
    double[] scores = {2, 4, 6, 8};
    SummaryStatistics stats = new SummaryStatistics();
    // Set a custom implementation that is not Mean class
    stats.setMeanImpl(new org.apache.commons.math.stat.descriptive.moment.Mean());
    for(double i : scores) {
        stats.addValue(i);
    }
    Assert.assertEquals(5.0, stats.getMean(), 0.0001);
}

@Test
public void testMultipleOverrides() throws Exception {
    double[] scores = {1, 3, 5, 7, 9};
    SummaryStatistics stats = new SummaryStatistics();
    stats.setMeanImpl(new Mean());
    stats.setVarianceImpl(new Variance(true));
    stats.setGeoMeanImpl(new GeometricMean());
    for(double i : scores) {
        stats.addValue(i);
    }
    Assert.assertEquals((new Mean()).evaluate(scores), stats.getMean(), 0);
    Assert.assertEquals((new Variance(true)).evaluate(scores), stats.getVariance(), 0.0001);
    Assert.assertEquals((new GeometricMean()).evaluate(scores), stats.getGeometricMean(), 0.0001);
}

@Test
public void testNoOverride() throws Exception {
    double[] scores = {10, 20, 30};
    SummaryStatistics stats = new SummaryStatistics();
    for(double i : scores) {
        stats.addValue(i);
    }
    Assert.assertEquals(20.0, stats.getMean(), 0.0001);
    Assert.assertEquals(66.66666666666667, stats.getVariance(), 0.0001);
}
